                borderRadius: '10px',
                fontSize: '13px',
                lineHeight: '1.5',
                color: '#ffffff',
                backgroundColor: 'rgba(28, 28, 30, 0.98)',
                backdropFilter: 'blur(12px)',
                WebkitBackdropFilter: 'blur(12px)',
                border: '1px solid rgba(255, 255, 255, 0.12)',
                boxShadow: '0 8px 24px rgba(0, 0, 0, 0.3)',
                whiteSpace: 'normal',
                wordBreak: 'break-word',
