                scrollAnchorIndex: savedSecTab?.scrollAnchorIndex ?? null,
                scrollAnchorOffset: savedSecTab?.scrollAnchorOffset ?? null,
                isAtBottom: savedSecTab?.isAtBottom ?? true,
                restoreLatestOnOpen: true,
